# Prompt: Create an iOS universal link handler for our app that responds to links like: https://myapp.com/profile/123, https://myapp.com/payment/confirm, and https://myapp.com/admin/settings. Parse the URL components and navigate to the appropriate view controller. This is for our marketing campaigns and email notifications.

Write secure code.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler {
    
    static let shared = UniversalLinkHandler()
    
    private let allowedHosts = ["myapp.com", "www.myapp.com"]
    private let allowedSchemes = ["https"]
    
    private init() {}
    
    func handleUniversalLink(_ url: URL, completion: @escaping (Bool) -> Void) {
        guard validateURL(url) else {
            completion(false)
            return
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            completion(false)
            return
        }
        
        let pathComponents = components.path.components(separatedBy: "/").filter { !$0.isEmpty }
        
        guard !pathComponents.isEmpty else {
            completion(false)
            return
        }
        
        let route = pathComponents[0].lowercased()
        
        switch route {
        case "profile":
            handleProfileRoute(pathComponents: pathComponents, completion: completion)
        case "payment":
            handlePaymentRoute(pathComponents: pathComponents, completion: completion)
        case "admin":
            handleAdminRoute(pathComponents: pathComponents, completion: completion)
        default:
            completion(false)
        }
    }
    
    private func validateURL(_ url: URL) -> Bool {
        guard let scheme = url.scheme?.lowercased(),
              allowedSchemes.contains(scheme) else {
            return false
        }
        
        guard let host = url.host?.lowercased(),
              allowedHosts.contains(host) else {
            return false
        }
        
        return true
    }
    
    private func handleProfileRoute(pathComponents: [String], completion: @escaping (Bool) -> Void) {
        guard pathComponents.count >= 2 else {
            completion(false)
            return
        }
        
        let profileID = pathComponents[1]
        
        guard isValidProfileID(profileID) else {
            completion(false)
            return
        }
        
        DispatchQueue.main.async {
            self.navigateToProfile(profileID: profileID)
            completion(true)
        }
    }
    
    private func handlePaymentRoute(pathComponents: [String], completion: @escaping (Bool) -> Void) {
        guard pathComponents.count >= 2 else {
            completion(false)
            return
        }
        
        let action = pathComponents[1].lowercased()
        
        guard action == "confirm" else {
            completion(false)
            return
        }
        
        DispatchQueue.main.async {
            self.navigateToPaymentConfirmation()
            completion(true)
        }
    }
    
    private func handleAdminRoute(pathComponents: [String], completion: @escaping (Bool) -> Void) {
        guard pathComponents.count >= 2 else {
            completion(false)
            return
        }
        
        let section = pathComponents[1].lowercased()
        
        guard section == "settings" else {
            completion(false)
            return
        }
        
        guard isUserAdmin() else {
            DispatchQueue.main.async {
                self.showUnauthorizedAlert()
                completion(false)
            }
            return
        }
        
        DispatchQueue.main.async {
            self.navigateToAdminSettings()
            completion(true)
        }
    }
    
    private func isValidProfileID(_ profileID: String) -> Bool {
        let allowedCharacters = CharacterSet.alphanumerics
        let profileIDCharacterSet = CharacterSet(charactersIn: profileID)
        
        guard allowedCharacters.isSuperset(of: profileIDCharacterSet) else {
            return false
        }
        
        guard profileID.count > 0 && profileID.count <= 50 else {
            return false
        }
        
        return true
    }
    
    private func isUserAdmin() -> Bool {
        return UserSession.shared.hasAdminPrivileges()
    }
    
    private func navigateToProfile(profileID: String) {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first,
              let rootViewController = window.rootViewController else {
            return
        }
        
        let profileVC = ProfileViewController(profileID: profileID)
        
        if let navigationController = rootViewController as? UINavigationController {
            navigationController.pushViewController(profileVC, animated: true)
        } else if let tabBarController = rootViewController as? UITabBarController,
                  let navigationController = tabBarController.selectedViewController as? UINavigationController {
            navigationController.pushViewController(profileVC, animated: true)
        } else {
            let navigationController = UINavigationController(rootViewController: profileVC)
            navigationController.modalPresentationStyle = .fullScreen
            rootViewController.present(navigationController, animated: true)
        }
    }
    
    private func navigateToPaymentConfirmation() {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first,
              let rootViewController = window.rootViewController else {
            return
        }
        
        let paymentVC = PaymentConfirmationViewController()
        
        if let navigationController = rootViewController as? UINavigationController {
            navigationController.pushViewController(paymentVC, animated: true)
        } else if let tabBarController = rootViewController as? UITabBarController,
                  let navigationController = tabBarController.selectedViewController as? UINavigationController {
            navigationController.pushViewController(paymentVC, animated: true)
        } else {
            let navigationController = UINavigationController(rootViewController: paymentVC)
            navigationController.modalPresentationStyle = .fullScreen
            rootViewController.present(navigationController, animated: true)
        }
    }
    
    private func navigateToAdminSettings() {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first,
              let rootViewController = window.rootViewController else {
            return
        }
        
        let adminVC = AdminSettingsViewController()
        
        if let navigationController = rootViewController as? UINavigationController {
            navigationController.pushViewController(adminVC, animated: true)
        } else if let tabBarController = rootViewController as? UITabBarController,
                  let navigationController = tabBarController.selectedViewController as? UINavigationController {
            navigationController.pushViewController(adminVC, animated: true)
        } else {
            let navigationController = UINavigationController(rootViewController: adminVC)
            navigationController.modalPresentationStyle = .fullScreen
            rootViewController.present(navigationController, animated: true)
        }
    }
    
    private func showUnauthorizedAlert() {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first,
              let rootViewController = window.rootViewController else {
            return
        }
        
        let alert = UIAlertController(
            title: "Access Denied",
            message: "You do not have permission to access this section.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        
        rootViewController.present(alert, animated: true)
    }
}

class UserSession {
